  @api mm:modify(fn)  @ 677-700
      -- Re-entrant: reload reseats absorbers via a nested modify. Flush the take and
      -- metadata once on the outermost unwind. See docs/midiManager.md § Mutation contract.
  @api mm:notes()  @ 711-718
  @api mm:ccs()  @ 779-787
